function solve(nums1) {
    const N = nums1.length;

    // 1. Pre-calculate parities P and counts
    const P = nums1.map(num => num % 2);
    let count[0] = 0;
    let count[1] = 0;
    for (const p of P) {
        count[p]++;
    }

    /**
     * Checks if it's possible to construct nums2 such that all elements have targetParity C.
     * @param {number} C Target parity (0 for even, 1 for odd)
     * @returns {boolean} True if achievable, false otherwise.
     */
    function canAchieveParity(C) {
        for (let i = 0; i < N; i++) {
            const p_i = P[i];

            // Option 1: nums2[i] = nums1[i]
            if (p_i === C) {
                // Satisfiable via Option 1
                continue;
            }

            // Option 2: nums2[i] = nums1[i] - nums1[j], j != i
            // We need P[j] = C XOR p_i
            const target_p_j = C ^ p_i;

            let found_j = false;

            if (target_p_j === 0) { // Need an even nums1[j]
                if (count[0] > 0) {
                    // If nums1[i] is even (p_i=0), we need at least one other even number.
                    if (p_i === 0) { 
                        if (count[0] >= 2) found_j = true;
                    } else { // nums1[i] is odd (p_i=1), we just need any even number.
                        if (count[0] >= 1) found_j = true;
                    }
                }
            } else { // target_p_j === 1. Need an odd nums1[j]
                if (count[1] > 0) {
                    // If nums1[i] is even (p_i=0), we just need any odd number.
                    if (p_i === 0) {
                        if (count[1] >= 1) found_j = true;
                    } else { // nums1[i] is odd (p_i=1), we need at least one other odd number.
                        if (count[1] >= 2) found_j = true;
                    }
                }
            }

            if (found_j) {
                // Satisfiable via Option 2
                continue;
            }

            // If neither option worked for index i
            return false;
        }

        // If all indices were satisfiable
        return true;
    }

    // Check if all can be even (C=0) or all can be odd (C=1)
    return canAchieveParity(0) || canAchieveParity(1);
}

